mapper.select:
select subject_id as subjectId, subject_code as subjectCode, subject_name as subjectName, subject_type as subjectType, balance_direction as balanceDirection, status, create_by as createBy, create_time as createTime, update_by as updateBy, update_time as updateTime, remark from fin_account_subject
and status = #{status}
order by subject_code asc

select auxiliary_id as auxiliaryId, auxiliary_type as auxiliaryType, item_code as itemCode, item_name as itemName, relation_id as relationId, status, create_by as createBy, create_time as createTime, update_by as updateBy, update_time as updateTime, remark from fin_auxiliary_item
and auxiliary_type = #{auxiliaryType}
order by auxiliary_type asc, item_code asc

select period_id as periodId, period_code as periodCode, start_date as startDate, end_date as endDate, close_status as closeStatus, close_by as closeBy, close_time as closeTime, create_by as createBy, create_time as createTime, update_by as updateBy, update_time as updateTime, remark from fin_fiscal_period
and close_status = #{closeStatus}
order by period_code desc
